fn solve(grid: Vec<Vec<i64>>, k: i64) -> i64 {
    if grid.is_empty() || grid[0].is_empty() {
        return 0;
    }

    let m = grid.len();
    let n = grid[0].len();
    let mut visited = vec![vec![false; n]; m];
    let mut count = 0;

    fn dfs(grid: &Vec<Vec<i64>>, visited: &mut Vec<Vec<bool>>, i: usize, j: usize) -> i64 {
        if i >= grid.len() || j >= grid[0].len() || grid[i][j] == 0 || visited[i][j] {
            return 0;
        }
        visited[i][j] = true;
        let mut total = grid[i][j];
        if i > 0 {
            total += dfs(grid, visited, i - 1, j);
        }
        if i + 1 < grid.len() {
            total += dfs(grid, visited, i + 1, j);
        }
        if j > 0 {
            total += dfs(grid, visited, i, j - 1);
        }
        if j + 1 < grid[0].len() {
            total += dfs(grid, visited, i, j + 1);
        }
        total
    }

    for i in 0..m {
        for j in 0..n {
            if grid[i][j] > 0 && !visited[i][j] {
                let island_sum = dfs(&grid, &mut visited, i, j);
                if island_sum % k == 0 {
                    count += 1;
                }
            }
        }
    }
    count
}
